  1→/**
  2→ * Protocol types for communication between the Rust core and TypeScript frontend.
  3→ *
  4→ * All messages are newline-delimited JSON over stdin/stdout. The core sends
  5→ * Request messages and receives Response messages back. Every message includes
  6→ * a protocol version for compatibility checking.
  7→ */
  8→
  9→export const PROTOCOL_VERSION = "0.1.0";
 10→export const FRONTEND_LANGUAGE = "typescript";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Request: Core → Frontend
 14→// ---------------------------------------------------------------------------
 15→
 16→export type SetupMode = "per_function" | "per_execution";
 17→
 18→export type SetupLevel = "session" | "file" | "function" | "execution";
 19→
 20→export interface SetupContextEntry {
 21→  level: SetupLevel;
 22→  context: unknown;
 23→}
 24→
 25→export interface SetupContextStack {
 26→  contexts: SetupContextEntry[];
 27→}
 28→
 29→export type GeneratorKind = "type_name" | "param_name";
 30→
 31→export type Command =
 32→  | "handshake"
 33→  | "analyze"
 34→  | "instrument"
 35→  | "execute"
 36→  | "setup"
 37→  | "teardown"
 38→  | "generate"
 39→  | "shutdown";
 40→
 41→export interface MockConfig {
 42→  symbol: string;
 43→  return_values: unknown[];
 44→  should_track_calls: boolean;
 45→  default_behavior: "return_generated" | "repeat_last" | "throw_error" | "passthrough";
 46→}
 47→
 48→interface BaseRequest {
 49→  protocol_version: string;
 50→  id: number;
 51→  command: Command;
 52→}
 53→
 54→export interface HandshakeRequest extends BaseRequest {
 55→  command: "handshake";
 56→  capabilities: string[];
 57→}
 58→
 59→export interface AnalyzeRequest extends BaseRequest {
 60→  command: "analyze";
 61→  file: string;
 62→  function?: string | null;
 63→  project_root?: string | null;
 64→}
 65→
 66→export interface InstrumentRequest extends BaseRequest {
 67→  command: "instrument";
 68→  file: string;
 69→  function: string;
 70→  mocks: MockConfig[];
 71→  project_root?: string | null;
 72→}
 73→
 74→export interface ExecuteRequest extends BaseRequest {
 75→  command: "execute";
 76→  function: string;
 77→  inputs: unknown[];
 78→  mocks: MockConfig[];
 79→  setup_context?: SetupContextStack | null;
 80→}
 81→
 82→export interface SetupRequest extends BaseRequest {
 83→  command: "setup";
 84→  file: string;
 85→  scope: string;
 86→  level: SetupLevel;
 87→  parent_context?: SetupContextStack | null;
 88→  project_root?: string | null;
 89→}
 90→
 91→export interface TeardownRequest extends BaseRequest {
 92→  command: "teardown";
 93→  scope: string;
 94→  level: SetupLevel;
 95→}
 96→
 97→export interface GenerateRequest extends BaseRequest {
 98→  command: "generate";
 99→  file: string;
100→  name: string;
101→  kind: GeneratorKind;
102→  recipe?: unknown;
103→  project_root?: string | null;
104→}
105→
106→export interface ShutdownRequest extends BaseRequest {
107→  command: "shutdown";
108→}
109→
110→export type Request =
111→  | HandshakeRequest
112→  | AnalyzeRequest
113→  | InstrumentRequest
114→  | ExecuteRequest
115→  | SetupRequest
116→  | TeardownRequest
117→  | GenerateRequest
118→  | ShutdownRequest;
119→
120→// ---------------------------------------------------------------------------
121→// Response: Frontend → Core
122→// ---------------------------------------------------------------------------
123→
124→export type ResponseStatus =
125→  | "handshake"
126→  | "analyze"
127→  | "instrument"
128→  | "execute"
129→  | "setup"
130→  | "teardown_ack"
131→  | "generate"
132→  | "shutdown_ack"
133→  | "error";
134→
135→/** Canonical error codes matching protocol/registry.yaml (11 codes). */
136→export const ALL_ERROR_CODES = [
137→  "file_not_found",
138→  "function_not_found",
139→  "parse_error",
140→  "instrumentation_failed",
141→  "execution_timeout",
142→  "execution_crash",
143→  "version_mismatch",
144→  "invalid_request",
145→  "compilation_error",
146→  "internal_error",
147→  "not_supported",
148→] as const;
149→
150→export type ErrorCode = (typeof ALL_ERROR_CODES)[number];
151→
152→interface BaseResponse {
153→  protocol_version: string;
154→  id: number;
155→  status: ResponseStatus;
156→}
157→
158→export interface HandshakeResponse extends BaseResponse {
159→  status: "handshake";
160→  frontend_version: string;
161→  language: string;
162→  capabilities: string[];
163→}
164→
165→export interface AnalyzeResponse extends BaseResponse {
166→  status: "analyze";
167→  functions: FunctionAnalysis[];
168→}
169→
170→export interface InstrumentResponse extends BaseResponse {
171→  status: "instrument";
172→  instrumented: boolean;
173→  output_file: string | null;
174→  instrumentable_line_count?: number;
175→}
176→
177→export interface ExecuteResponse extends BaseResponse {
178→  status: "execute";
179→  return_value: unknown;
180→  thrown_error: ErrorInfo | null;
181→  branch_path: BranchDecision[];
182→  lines_executed: number[];
183→  calls_to_external: ExternalCall[];
184→  path_constraints: SymConstraint[];
185→  side_effects: SideEffect[];
186→  performance: PerformanceMetrics;
187→  capture_truncation?: TruncationInfo;
188→  scope_events?: TraceEvent[];
189→}
190→
191→export interface SetupResponse extends BaseResponse {
192→  status: "setup";
193→  setup_context: unknown;
194→}
195→
196→export interface TeardownAckResponse extends BaseResponse {
197→  status: "teardown_ack";
198→}
199→
200→export interface GenerateResponse extends BaseResponse {
201→  status: "generate";
202→  value: unknown;
203→  generator_id: string;
204→  recipe?: unknown;
205→}
206→
207→export interface ShutdownAckResponse extends BaseResponse {
208→  status: "shutdown_ack";
209→}
210→
211→export interface ErrorResponse extends BaseResponse {
212→  status: "error";
213→  code: ErrorCode;
214→  message: string;
215→  details?: unknown;
216→}
217→
218→export type Response =
219→  | HandshakeResponse
220→  | AnalyzeResponse
221→  | InstrumentResponse
222→  | ExecuteResponse
223→  | SetupResponse
224→  | TeardownAckResponse
225→  | GenerateResponse
226→  | ShutdownAckResponse
227→  | ErrorResponse;
228→
229→// ---------------------------------------------------------------------------
230→// Supporting types
231→// ---------------------------------------------------------------------------
232→
233→/** A literal constant extracted from source code for use as a candidate test input. */
234→export type LiteralValue =
235→  | { type: "int"; value: number }
236→  | { type: "float"; value: number }
237→  | { type: "str"; value: string }
238→  | { type: "bool"; value: boolean }
239→  | { type: "regex"; pattern: string };
240→
241→export interface CryptoBoundary {
242→  symbol: string;
243→  source_module: string;
244→  direction: "encrypt" | "decrypt" | "both";
245→  output: "ciphertext" | "plaintext" | "key" | "hash" | "signature" | "verified";
246→  param_roles: Record<string, "key" | "data" | "iv" | "nonce" | "tag" | "aad" | "algorithm">;
247→  call_sites: number[];
248→}
249→
250→export interface FunctionAnalysis {
251→  name: string;
252→  exported?: boolean;
253→  params: ParamInfo[];
254→  branches: BranchInfo[];
255→  dependencies: ExternalDependency[];
256→  return_type: TypeInfo;
257→  start_line: number;
258→  end_line: number;
259→  literals?: LiteralValue[];
260→  crypto_boundaries?: CryptoBoundary[];
261→}
262→
263→export interface ParamInfo {
264→  name: string;
265→  type: TypeInfo;
266→  type_name?: string;
267→}
268→
269→/** Well-known complex types beyond primitives and structural types. */
270→export type ComplexKind =
271→  | "date" | "date_time" | "time" | "duration"
272→  | "reg_exp" | "char" | "symbol"
273→  | "big_int" | "big_decimal" | "complex" | "rational" | "range"
274→  | "buffer" | "bit_set"
275→  | "error" | "option" | "result"
276→  | "closure" | "iterator"
277→  | "url" | "ip_address"
278→  | "uuid"
279→  | "path"
280→  | "money" | "sem_ver" | "email" | "mime_type" | "color" | "geo_point" | "locale"
281→  | "rune" | "go_byte";
282→
283→export type TypeInfo =
284→  | { kind: "int" }
285→  | { kind: "float" }
286→  | { kind: "str" }
287→  | { kind: "bool" }
288→  | { kind: "unknown" }
289→  | { kind: "array"; element: TypeInfo }
290→  | { kind: "object"; fields: [string, TypeInfo][] }
291→  | { kind: "union"; variants: TypeInfo[] }
292→  | { kind: "nullable"; inner: TypeInfo }
293→  | { kind: "complex"; complex_kind: ComplexKind; metadata?: Record<string, unknown>; inner?: TypeInfo }
294→  | { kind: "opaque"; label: string };
295→
296→export interface BranchInfo {
297→  id: number;
298→  line: number;
299→  condition_text: string;
300→  condition: SymExpr | null;
301→  branch_type: BranchType;
302→}
303→
304→export type BranchType =
305→  | "if"
306→  | "else_if"
307→  | "switch"
308→  | "ternary"
309→  | "logical_and"
310→  | "logical_or"
311→  | "while"
312→  | "for";
313→
314→export type SymExpr =
315→  | { kind: "param"; name: string; path: string[] }
316→  | SymExprConst
317→  | { kind: "bin_op"; op: BinOpKind; left: SymExpr; right: SymExpr }
318→  | { kind: "un_op"; op: UnOpKind; operand: SymExpr }
319→  | { kind: "call"; name: string; receiver: SymExpr | null; args: SymExpr[] }
320→  | { kind: "unknown" };
321→
322→/** Const variant of SymExpr. Flattened to match Rust serde serialization. */
323→export type SymExprConst =
324→  | { kind: "const"; type: "int"; value: number }
325→  | { kind: "const"; type: "float"; value: number }
326→  | { kind: "const"; type: "str"; value: string }
327→  | { kind: "const"; type: "bool"; value: boolean }
328→  | { kind: "const"; type: "null" }
329→  | { kind: "const"; type: "undefined" }
330→  | { kind: "const"; type: "complex"; value: { kind: ComplexKind; repr: SymExprConst } };
331→
332→export type BinOpKind =
333→  | "eq" | "ne" | "lt" | "le" | "gt" | "ge"
334→  | "add" | "sub" | "mul" | "div" | "mod"
335→  | "and" | "or"
336→  | "bitwise_and" | "bitwise_or" | "bitwise_xor"
337→  | "in" | "instance_of";
338→
339→export type UnOpKind = "not" | "neg" | "bitwise_not" | "typeof";
340→
341→export interface BranchDecision {
342→  branch_id: number;
343→  line: number;
344→  taken: boolean;
345→  constraint: SymConstraint;
346→}
347→
348→export type ScopeEvent =
349→  | { kind: "loop_enter"; loop_id: number }
350→  | { kind: "loop_exit"; loop_id: number }
351→  | { kind: "call_enter"; call_site_id: number }
352→  | { kind: "call_exit"; call_site_id: number };
353→
354→export type TraceEvent =
355→  | { type: "branch"; decision: BranchDecision }
356→  | { type: "scope"; event: ScopeEvent };
357→
358→export type SymConstraint =
359→  | { kind: "expr"; expr: SymExpr }
360→  | { kind: "unknown"; hint: string };
361→
362→export interface ExternalCall {
363→  symbol: string;
364→  args: unknown[];
365→  return_value: unknown;
366→}
367→
368→export interface ExternalDependency {
369→  kind: DependencyKind;
370→  symbol: string;
371→  source_module: string;
372→  return_type: TypeInfo;
373→  param_types: TypeInfo[];
374→  call_sites: number[];
375→}
376→
377→export type DependencyKind =
378→  | "function_call"
379→  | "method_call"
380→  | "property_access"
381→  | "module_import";
382→
383→export type SideEffect =
384→  | { kind: "console_output"; level: string; message: string }
385→  | { kind: "file_write"; path: string; content: string }
386→  | { kind: "network_request"; method: string; url: string; body: unknown }
387→  | { kind: "environment_read"; variable: string; value: string | null }
388→  | { kind: "global_mutation"; name: string }
389→  | { kind: "thrown_error"; error_type: string; message: string; stack: string | null }
390→  | { kind: "global_state_change"; variable: string; before: unknown; after: unknown };
391→
392→export type ErrorCategory = "validation" | "runtime" | "infrastructure" | "unknown";
393→
394→export interface ErrorInfo {
395→  error_type: string;
396→  message: string;
397→  stack: string | null;
398→  error_category?: ErrorCategory;
399→}
400→
401→export interface TruncationInfo {
402→  was_truncated: boolean;
403→  original_lines: number;
404→  original_bytes: number;
405→}
406→
407→export interface PerformanceMetrics {
408→  wall_time_ms: number;
409→  cpu_time_us: number;
410→  heap_used_bytes: number;
411→  heap_allocated_bytes: number;
412→}
